cartSetup.query:
mutation AuthoritativeLifecycleCartSetup($functionId: String!) {
  cartTransformCreate(functionId: $functionId) {
    cartTransform { id }
    userErrors { field message code }
  }
}

functionValidationsHydrate.query:
query FunctionValidationsHydrate($after: String) {
  validations(first: 100, after: $after) {
    nodes {
      id
      title
      enabled
      blockOnFailure
      shopifyFunction {
        id
        title
        handle
        apiType
        description
        appKey
        app {
          __typename
          id
          title
          handle
          apiKey
        }
      }
      metafields(first: 100) {
        nodes {
          id
          namespace
          key
          type
          value
          updatedAt
        }
      }
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

functionCartTransformsHydrate.query:
query FunctionCartTransformsHydrate($after: String) {
  cartTransforms(first: 100, after: $after) {
    nodes {
      id
      functionId
      blockOnFailure
      metafields(first: 100) {
        nodes {
          id
          namespace
          key
          type
          value
          compareDigest
          ownerType
          createdAt
          updatedAt
        }
      }
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

secondCartFunctionHydrate.query:
query FunctionHydrateById($id: String!) {
  shopifyFunction(id: $id) {
    id
    title
    apiType
    description
    appKey
    app {
      __typename
      id
      title
      apiKey
    }
  }
}

preflight.query:
mutation AuthoritativeLifecyclePreflight(
  $validationFunctionId: String!
  $secondCartFunctionId: String!
) {
  validationLimit: validationCreate(
    validation: {
      functionId: $validationFunctionId
      title: "Twenty sixth active validation"
      enable: true
    }
  ) {
    validation { id }
    userErrors { field message code }
  }
  reusedValidationFunction: cartTransformCreate(functionId: $validationFunctionId) {
    cartTransform { id }
    userErrors { field message code }
  }
  secondCartTransform: cartTransformCreate(functionId: $secondCartFunctionId) {
    cartTransform { id }
    userErrors { field message code }
  }
}

